export function parseInitialItemMaster(): PurchaseItemMaster[] {
  const lines = INITIAL_ITEM_MASTER_CSV.trim().split('\n');
  return lines.slice(1).map(line => {
    const c = line.split(',');
    return {
      partNo: c[0] || '',
      costType: c[1] || '',
      purchaseType: c[2] || '',
      materialType: c[3] || '',
      process: c[4] || '',
      customer: c[5] || '',
    };
  }).filter(m => m.partNo);
}

function splitCSV(line: string): string[] {
  const result: string[] = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') { inQuotes = !inQuotes; }
    else if (ch === ',' && !inQuotes) { result.push(current.trim()); current = ''; }
    else { current += ch; }
  }
  result.push(current.trim());
  return result;
}

export function parseInitialSummary(): PurchaseMonthlySummary[] {
  const lines = INITIAL_SUMMARY_CSV.trim().split('\n');
  return lines.slice(1).map(line => {
    const c = splitCSV(line);
    return {
      year: parseInt(c[0]) || 2025,
      month: c[1] || '',
      supplier: c[2] || '',
      partNo: c[3] || '',
      partName: c[4] || '',
      spec: c[5] || '',
      unit: c[6] || '',
      salesQty: parseFloat(c[7]) || 0,
      closingQty: parseFloat(c[8]) || 0,
      unitPrice: parseFloat(c[9]) || 0,
      amount: parseFloat(c[10]) || 0,
      location: c[11] || '',
      costType: c[12] || '',
      purchaseType: c[13] || '',
      materialType: c[14] || '',
      process: c[15] || '',
      customer: c[16] || '',
      remark: c[17] || '',
      closingMonth: '',
    };
  }).filter(d => d.supplier);
}
